    background-color: var(--bg-elevated);
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.12);
    border: 1px solid var(--border-card);
}

/* ── Content (title + text) ── */
.content-container{
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: flex-start;
    user-select: none;
    gap: 0.5rem;
}
.feed-text-content-container{
    display: flex;
    flex-direction: column;
    width: 100%;
    height: 100%;
    justify-content: flex-start;
    align-items: flex-start;
    gap: 0.35rem;
}
.feed-title-content{
    display: flex;
    justify-content: center;
    align-items: center;
}

.feed-title{
    margin: 0;
    padding: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 1.1rem;
    font-weight: 700;
    line-height: 1.45;
    letter-spacing: -0.025rem;
    color: var(--text-heading);
}
.feed-text-content{
    padding: 0;
    margin: 0;
    font-family: var(--font-serif);
    font-weight: 400;
    color: var(--text-body);
    line-height: 1.7;
    font-size: 0.88rem;
    letter-spacing: 0.005rem;
}


/* ── Icon bar ── */
.card-icons-container{
    display: flex;
    flex-wrap: wrap;
    width: 100%;
    padding: 0.5rem 1.15rem 0.85rem 1.15rem;
    min-height: 22px;
    align-items: center;
    justify-content: flex-start;
    gap: 0.5rem;
    box-sizing: border-box;
    border-top: 1px solid var(--border-card);
}
#card-icons{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.35rem;
    border-radius: 50%;
    transition: background-color 0.2s ease;
    gap: 0.3rem;
}
#card-icons-view{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.1rem;
    border-radius: 50%;
    transition: background-color 0.2s ease;
    gap: 0.3rem;
}
.card-icons{
    display: flex;
    width: fit-content;
    height: fit-content;
    justify-content: center;
    align-items: center;
}
.icon-container{
    display: flex;
    justify-content: center;
    align-items: center;
}
.icon-container p{
    font-family: var(--font-ui);
}

.like-button:hover .svg-like path{
    fill: rgb(255, 116, 116);
}
.like-button:hover{
    background-color: rgba(255, 161, 161, 0.12);
}
.comment-button:hover{
    background-color: rgba(212, 168, 83, 0.12);
}
.comment-button:hover .svg-comment path{
    fill: var(--accent-amber);
}
.bookmark-button:hover{
    background-color: rgba(245, 158, 11, 0.12);
}
.bookmark-button:hover .svg-bookmark path{
    fill: var(--accent-amber);
}

/* ── Bookmark bounce animation ── */
@keyframes bookmark-bounce {
    0% { transform: scale(1); }
    30% { transform: scale(0.85); }
    60% { transform: scale(1.2); }
    100% { transform: scale(1); }
}
.bookmark-button.bookmark-bouncing .svg-bookmark {
    animation: bookmark-bounce 400ms var(--ease-spring, cubic-bezier(0.34, 1.56, 0.64, 1));
}

/* ── Reading time pill ── */
.reading-time-container{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.2rem 0.7rem;
    background-color: var(--bg-pill);
    border: 1px solid var(--border-card);
    border-radius: 10px;
    margin-left: auto;
}
.reading-time-text{
    padding: 0;
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.62rem;
    font-weight: 550;
    color: var(--accent-sage);
    letter-spacing: 0.01rem;
}

/* ── Repost card ── */
.repost-header-badge{
    display: flex;
    align-items: center;
    gap: 0.35rem;
    padding: 0.5rem 1.15rem 0;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--text-faint);
}
.repost-header-name{
    font-weight: 650;
    color: var(--text-secondary);
    cursor: pointer;
}
.repost-header-name:hover{
    text-decoration: underline;
    color: var(--accent-sage);
}
.repost-caption-text{
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 450;
    color: var(--text-heading);
    line-height: 1.6;
    white-space: pre-wrap;
    word-break: break-word;
}
.repost-embedded-card{
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    padding: 0.75rem;
    background: var(--bg-secondary);
    border: 1px solid var(--border-card);
    border-radius: 10px;
    cursor: pointer;
    transition: border-color 0.2s ease, box-shadow 0.2s ease;
}
.repost-embedded-card:hover{
    border-color: var(--accent-sage);
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.06);
}
.repost-embedded-author{
    display: flex;
    align-items: center;
    gap: 0.35rem;
}
.repost-embedded-avatar-wrap{
    display: flex;
    align-items: center;
    justify-content: center;
    width: 18px;
    height: 18px;
    border-radius: 50%;
    flex-shrink: 0;
}
.repost-embedded-avatar-wrap.avatar-ring-legend{
    width: 22px;
    height: 22px;
    border-width: 1.5px;
    box-shadow:
        0 0 3px 0.5px rgba(255, 215, 0, 0.4),
        0 0 6px 1px rgba(255, 215, 0, 0.25);
}
.repost-embedded-avatar-wrap.avatar-ring-og{
    width: 22px;
    height: 22px;
    border-width: 1.5px;
    box-shadow:
        0 0 3px 0.5px rgba(155, 89, 255, 0.4),
        0 0 6px 1px rgba(155, 89, 255, 0.25);
}
.repost-embedded-avatar{
    width: 100%;
    height: 100%;
    border-radius: 50%;
    object-fit: cover;
    display: block;
}
.repost-embedded-name{
    font-family: var(--font-ui);
    font-size: 0.74rem;
    font-weight: 600;
    color: var(--text-secondary);
}
.repost-embedded-title{
    margin: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 0.92rem;
    font-weight: 650;
    color: var(--text-heading);
    line-height: 1.35;
}
.repost-embedded-text{
    margin: 0;
    font-family: var(--font-serif);
    font-size: 0.8rem;
    font-weight: 400;
    color: var(--text-body);
    line-height: 1.55;
}
.repost-unavailable{
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 1.5rem;
    background: var(--bg-secondary);
    border: 1px dashed var(--border-card);
    border-radius: 10px;
    font-family: var(--font-ui);
    font-size: 0.8rem;
    font-weight: 500;
    color: var(--text-faint);
}
.repost-button:hover{
    background-color: rgba(72, 208, 135, 0.12);
}
.repost-button:hover .svg-repost path{
    fill: var(--accent-sage);
}
.repost-toast{
    position: fixed;
    bottom: 2rem;
    left: 50%;
    transform: translateX(-50%);
    z-index: 1000;
    padding: 0.5rem 1.2rem;
    background: var(--accent-sage);
    color: #fff;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    border-radius: 8px;
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.15);
}

.sample-content-show{
    width: 100%;
    height: 100%;
    background-color: var(--bg-primary);
    z-index: 10;
}

