    .reading-time-text{
        font-size: 0.58rem;
        white-space: nowrap;
    }

    .user-post-settings{
        position: absolute;
        top: 0.5rem;
        right: 0.75rem;
        flex-shrink: 0;
        color: var(--text-heading);
