.editor-container {
    display: flex;
    flex-direction: column;
    width: 100%;
    max-width: 720px;
    height: 80%;
    min-height: 0;
    overflow: hidden;
    background-color: var(--editor-bg);
    color: var(--editor-text);
    border-radius: 16px;
    padding: 1rem 1.5rem;
    box-shadow: var(--shadow-modal);
}

.editor-mode-shell {
    position: relative;
    display: flex;
    flex-direction: column;
    flex: 1;
    min-height: 0;
    overflow: hidden;
}

/* ── Close button row ── */
.editor-close-bttn-container {
    display: flex;
    width: 100%;
    justify-content: flex-end;
    align-items: center;
}
.editor-close-bttn {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0.4rem;
    border: none;
    background: transparent;
    border-radius: 50%;
    cursor: pointer;
    color: var(--text-muted);
    transition: background-color 0.15s ease, color 0.15s ease, transform 0.15s ease;
}
.editor-close-bttn svg {
    fill: var(--text-muted);
    transition: fill 0.15s ease;
}
.editor-close-bttn:hover {
    background-color: var(--bg-pill);
    color: var(--editor-text);
    transform: scale(1.05);
}
.editor-close-bttn:hover svg {
    fill: var(--editor-text);
}

