@keyframes skel-shimmer {
    0% { background-position: -400px 0; }
    100% { background-position: 400px 0; }
}

.skel-feed {
    display: flex;
    flex-direction: column;
    gap: 16px;
    padding: 8px 16px;
    width: 100%;
    box-sizing: border-box;
}

@media (max-width: 480px) {
    .skel-feed {
        padding: 8px 10px;
    }
}

.skel-card {
    background: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 12px;
    padding: 18px 20px;
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.skel-shimmer {
    background: linear-gradient(
        90deg,
        var(--bg-secondary) 25%,
        var(--bg-hover) 50%,
        var(--bg-secondary) 75%
    );
    background-size: 800px 100%;
    animation: skel-shimmer 1.5s ease-in-out infinite;
    border-radius: 6px;
}

.skel-header {
    display: flex;
    align-items: center;
    gap: 10px;
}

.skel-avatar {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    flex-shrink: 0;
}

.skel-meta {
    display: flex;
    flex-direction: column;
    gap: 6px;
    flex: 1;
}

.skel-name {
    width: 120px;
    height: 12px;
}

.skel-date {
    width: 80px;
    height: 10px;
}

.skel-title {
    width: 75%;
    height: 16px;
}

.skel-line {
    width: 100%;
    height: 11px;
}

.skel-line--short {
    width: 60%;
}

.skel-actions {
    display: flex;
    gap: 16px;
    margin-top: 4px;
}

.skel-action {
    width: 48px;
    height: 20px;
    border-radius: 10px;
}

